import{_ as e,c as r,o as t,a as o}from"./app.09261a68.js";const f=JSON.parse('{"title":"CRD && Operator","description":"","frontmatter":{"date":"2022-12-28T00:00:00.000Z","recommend":5},"headers":[{"level":2,"title":"CRD","slug":"crd","link":"#crd","children":[]},{"level":2,"title":"Operator","slug":"operator","link":"#operator","children":[]}],"relativePath":"zh/cloud-native/kubernetes/crd-operator.md"}'),a={name:"zh/cloud-native/kubernetes/crd-operator.md"},c=o('<h1 id="crd-operator" tabindex="-1">CRD &amp;&amp; Operator <a class="header-anchor" href="#crd-operator" aria-hidden="true">#</a></h1><p><code>CRD &amp;&amp; Operator</code>是指使用<a href="#crd">CRD</a>来定义资源属性并由<a href="#operator">Operator</a>服务组件进行解析和管理。</p><h2 id="crd" tabindex="-1">CRD <a class="header-anchor" href="#crd" aria-hidden="true">#</a></h2><p><a href="https://kubernetes.io/zh-cn/docs/concepts/extend-kubernetes/api-extension/custom-resources/#customresourcedefinitions" target="_blank" rel="noreferrer">CRD(Custom Resource Definition)</a>是 Kubernetes（v1.7+）为提高可扩展性，让开发者去自定义资源的一种方式。其存在形式与Pod、Service等Kubernetes原生资源相同，都是可以解析为<code>yaml</code>或<code>json</code>的属性集合。</p><h2 id="operator" tabindex="-1">Operator <a class="header-anchor" href="#operator" aria-hidden="true">#</a></h2><p><a href="https://kubernetes.io/zh-cn/docs/concepts/extend-kubernetes/operator/" target="_blank" rel="noreferrer">Operator</a>是Kubernetes的一种扩展模式，可以监听Kubernetes环境中的资源变化(增删改等事件)，并快速做出反应。<code>Operator</code>通常由开发者自定义操作逻辑，以微服务的形式部署于kubernetes环境中。</p><p><code>Operator</code>常用于解析<code>CRD</code>，可以将<code>CRD</code>资源解析为一系列Kubernetes原生资源、更新<code>CRD</code>状态等。</p>',7),d=[c];function n(s,p,i,h,l,u){return t(),r("div",null,d)}const m=e(a,[["render",n]]);export{f as __pageData,m as default};
